export interface WorkshopConcludeFinalVersionRule {
  "status_rule": "conclude is admitted only while the workshop is in_review and every later mutation is rejected as terminal";
  "selection_rule": "final_version_id must resolve to an existing durable version link that equals the currently selected workshop version";
  "completeness_rule": "authoritative Registry readback must expose a complete StrategySpec document in the caller tenant/user scope before conclusion";
  "digest_rule": "the readback document sha256 must match the immutable durable version-link digest; a mismatch fails the command with a durable failed receipt";
  "atomicity_rule": "terminal session fields, the concluded audit event, and the completed receipt commit in one store transaction";
}

export interface WorkshopOperationDurabilityRule {
  "receipt_rule": "every admitted operation persists a postgres command receipt keyed by tenant/user/workshop/operation/idempotency-key that survives BFF restart";
  "replay_rule": "an exact duplicate request replays the recorded receipt and downstream IDs without re-dispatching research, consultation, or conclusion";
  "failure_rule": "downstream rejection, timeout, or projection failure records a durable failed receipt; the same key then returns COMMAND_PREVIOUSLY_FAILED and a new key may retry";
  "compensation_rule": "a consultation opened downstream whose workshop commit fails is cancelled and the compensation is recorded on the failed receipt";
}

